import java.io.*;
import org.apache.commons.text.StringEscapeUtils;

public class XSSFixedCode {
    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));

        System.out.println("Enter your name:");
        String name = br.readLine();

        // Sanitize the user input to prevent XSS
        String sanitizedName = StringEscapeUtils.escapeHtml4(name);

        System.out.println("Hello, " + sanitizedName + "!");

        // Now, if an attacker enters "<script>alert('XSS Attack!')</script>" as the input,
        // it will be displayed as plain text without executing any scripts.
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
